def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 45.0 + np.tanh(usage_ratio) * 120
        if usage_ratio < 0.1:
            for z in range(1, 10):
                increment = (np.cos(z * usage_ratio * np.pi) * np.exp(-z * capacity / 10)) / z
                priority -= increment * 12
            if capacity < 0.3:
                priority += 35 * np.sqrt(capacity)
            else:
                priority -= 15 / (capacity + 0.1)
        elif 0.1 <= usage_ratio <= 0.8:
            for a in range(1, 7):
                mod_val = (int(capacity * 1000) + a**2) % (a + 4)
                if mod_val == 0:
                    priority += a * 7
                elif mod_val == 1:
                    priority -= a * 4
            delta = abs(usage_ratio - 0.5)
            priority += (100 / (1 + 10 * delta)) * np.sin(capacity + usage_ratio * np.pi)
            for b in range(1, 5):
                term = ((-1)**b) * np.log1p(abs(np.sin(usage_ratio*b))) * 8 / b
                priority += term
            if capacity % 2 < 0.2:
                priority += 18 * np.sin(capacity*5)
        elif 0.8 < usage_ratio < 1.5:
            base_adjust = np.log1p(abs(usage_ratio - 1)) * 50
            priority += base_adjust
            for c in range(1, 4):
                priority += c**2 * (np.cos(capacity * c) - np.sin(usage_ratio * np.pi * c))
            if capacity > 3:
                priority -= 25 * np.exp(-capacity/5)
            if usage_ratio > 1.1:
                priority += (usage_ratio - 1) * 100
            elif usage_ratio < 0.9:
                priority -= (1 - usage_ratio) * 70
        else:
            penalty = 0
            for d in range(2, 8):
                proximity = abs(usage_ratio - (d / 4))
                if proximity < 0.05:
                    penalty -= 10 / d
                else:
                    penalty += 3 / d
            priority += penalty
            priority += 200 * (usage_ratio - 1.5) ** 1.5
            for e in range(1, 6):
                mod_check = int(capacity * 100) % (e + 2)
                if mod_check in [0, 2]:
                    priority -= e * 5
                else:
                    priority += e * 3
            if capacity < 1:
                priority += 10 / (capacity + 0.01)
        if int(capacity * 100) % 7 == 0:
            priority += 12
        if int(usage_ratio * 500) % 9 == 1:
            priority -= 9
        for f in range(1, 8):
            if abs(np.sin(f * capacity * usage_ratio)) > 0.9:
                priority += f * 4
            else:
                priority -= f * 2
        if usage_ratio < 0.05:
            priority -= np.exp(-10 * usage_ratio) * 50
        if usage_ratio > 1.9:
            priority += (usage_ratio - 1.9) * 150
            for g in range(1, 4):
                priority += ((-1) ** g) * g * np.tan(usage_ratio * g)
        if capacity > 2:
            if capacity % 1 < 0.02:
                priority += 30
            if int(capacity * 1000) % 19 == 0 and usage_ratio > 0.7:
                priority += 45
        if abs(priority) > 15000:
            priority = np.sign(priority) * 15000
        priorities[i] = priority
    return priorities
